(function() {
  if (document.readyState !== 'loading') {
    initAccordionJS();
  } else {
    document.addEventListener('DOMContentLoaded', initAccordionJS);
  }

  function initAccordionJS() {
    const botones = document.querySelectorAll("[selector='accordiones'] .btn-primary");
    botones.forEach(btn => {
      btn.removeEventListener('click', toggleOpenClass);
      btn.addEventListener('click', toggleOpenClass);
    });
  }

  function toggleOpenClass(evt) {
    this.classList.toggle("open");
  }

  return '';
  
})();

setTimeout(() => {
  const modalComponent = document.querySelector('[custom-css-selector="btn_preventivo"]');
  if (!modalComponent || !modalComponent.__vue__) return;

  const vueInstance = modalComponent.__vue__;

  vueInstance.$root.$on('bv::modal::show', (bvEvent, modalId) => {
    const modal = bvEvent.vueTarget;

    if (modalId === 'modal_preventivo') {
      modal.onOk = () => {
  const loader = document.getElementById('global-loader-overlay');
  const submitBtn = document.querySelector('button[name="btn_submit_real"]');

  // 1️⃣ Solo validar frm_cot_seleccion_procede si la decisión es APROBADA
  const frm_respCot_decision = this.frm_respCot_decision;
  const esAprobada = String(frm_respCot_decision || "")
    .trim()
    .toUpperCase() === "APROBADA";

  if (esAprobada) {
    // 2️⃣ Validación de una opción de cotización (solo cuando es APROBADA)
    const frm_cot_seleccion_procede = this.frm_cot_seleccion_procede;

    const cot_seleccionOk =
      String(frm_cot_seleccion_procede || "").trim().toLowerCase() === "true";

    if (!cot_seleccionOk) {
      vueInstance.$root.$bvModal.show("modal_opcion_cotizacion_accion_requerida");
      modal.hide();

      setTimeout(() => {
        if (loader) loader.classList.remove("show");
      }, 350);

      return; // corta aquí solo en caso de APROBADA sin selección válida
    }
  }

  // ✅ Si no es APROBADA, o si es APROBADA y pasó la validación, continúa normal
  if (submitBtn) submitBtn.click();

  setTimeout(() => {
    const erroresVisibles = Array.from(document.querySelectorAll('.invalid-feedback'))
      .filter(div => {
        const visible = div.offsetParent !== null;
        const mensaje = div.textContent.trim().toLowerCase();
        return visible && (
          mensaje.includes("campo requerido") ||
          mensaje.includes("debe ser igual o después de")
        );
      });

    console.log("🔍 Errores visibles encontrados:", erroresVisibles.length);

    if (erroresVisibles.length === 0 && loader) {
      loader.classList.add('show');
      console.log("✅ Mostrando loader: no hay errores visibles");
    } else {
      console.log("❌ No se muestra loader: errores visibles encontrados");
    }
  }, 300);

  modal.hide();
};

    }
  });
}, 500);

(function () {
  const overlay = document.getElementById("global-loader-overlay");
  const textEl  = document.getElementById("global-loader-text");
  if (!overlay || !textEl) return;

  const mensajes = ["Procesando...", "Cargando...", "Validando...", "Un momento..."];
  let i = 0;
  let timer = null;

  const start = () => {
    if (timer) return; // ya está corriendo
    i = 0;
    textEl.textContent = mensajes[i];
    timer = setInterval(() => {
      // si el overlay ya no está visible, detén el timer
      if (overlay.offsetParent === null) return stop();
      i = (i + 1) % mensajes.length;
      textEl.textContent = mensajes[i];
    }, 2000);
  };

  const stop = () => {
    if (timer) clearInterval(timer);
    timer = null;
    textEl.textContent = "Procesando...";
  };

  // Exponer funciones por si quieres controlarlas desde tu código
  window.loaderTextRotateStart = start;
  window.loaderTextRotateStop = stop;
})();

